}

function listEnvelope<T>(data: T[], page = 1, perPage = 25) {
  const start = (page - 1) * perPage;
  const slice = data.slice(start, start + perPage);
  return envelope(slice, { page, per_page: perPage, total: data.length });
}

export const handlers = [
