            <Trash2 className="mr-2 h-4 w-4" /> Delete
          </Button>
        </div>
      </div>

      <div className="grid gap-6 lg:grid-cols-2">
        {/* Pipeline Config */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Pipeline Configuration</CardTitle>
          </CardHeader>
